import { useState, useEffect } from "react";
import AuthModal from "./AuthModal";

export default function Header({ onLogout, onLogin }) {
    const [username, setUsername] = useState(localStorage.getItem("username"));
    const [showAuth, setShowAuth] = useState(false);

    useEffect(() => {
        const stored = localStorage.getItem("username");
        if (stored) setUsername(stored);
    }, []);

    const handleAuthed = (name) => {
        localStorage.setItem("username", name);
        setUsername(name);
        onLogin?.(name);
    };

    const logout = () => {
        localStorage.removeItem("username");
        setUsername(null);
        onLogout?.();
    };

    return (
        <>
            <header style={{
                display:"flex", justifyContent:"space-between",
                alignItems:"center", padding:"10px 16px", background:"#eee"
            }}>
                <h2 style={{margin:0}}>VLR Clone</h2>
                <div>
                    {username ? (
                        <>
                            <span>Welcome, <strong>{username}</strong></span>
                            <button style={{marginLeft:10}} onClick={logout}>Logout</button>
                        </>
                    ) : (
                        <button onClick={()=>setShowAuth(true)}>Login</button>
                    )}
                </div>
            </header>

            {showAuth && (
                <AuthModal
                    onClose={()=>setShowAuth(false)}
                    onAuthed={handleAuthed}
                />
            )}
        </>
    );
}
